package com.paper.reviewer.history;
import com.paper.reviewer.common.BusinessException;import com.paper.reviewer.database.mapper.*;import com.paper.reviewer.export.repository.ExportRepository;import com.paper.reviewer.paper.domain.Paper;import com.paper.reviewer.paper.repository.PaperRepository;import com.paper.reviewer.review.repository.ReviewRepository;import com.paper.reviewer.rereview.repository.ReReviewRepository;import com.paper.reviewer.storage.service.LocalFileStorageService;import org.junit.jupiter.api.Test;import java.nio.file.Path;import java.time.LocalDateTime;import java.util.*;import static org.assertj.core.api.Assertions.*;import static org.mockito.Mockito.*;
class HistoryServiceTest{
 private final PaperRepository papers=mock(PaperRepository.class);private final ReviewRepository reviews=mock(ReviewRepository.class);private final ReReviewRepository rereviews=mock(ReReviewRepository.class);private final ReviewMapper reviewMapper=mock(ReviewMapper.class);private final RereviewMapper rereviewMapper=mock(RereviewMapper.class);private final PaperMapper paperMapper=mock(PaperMapper.class);private final ExportRepository exports=mock(ExportRepository.class);private final LocalFileStorageService storage=mock(LocalFileStorageService.class);private final HistoryService service=new HistoryService(papers,reviews,rereviews,reviewMapper,rereviewMapper,paperMapper,exports,storage);
 @Test void cannotReadAnotherUsersPaper(){when(papers.findOwnedById(2,9)).thenReturn(Optional.empty());assertThatThrownBy(()->service.detail(2,9)).isInstanceOf(BusinessException.class);}
 @Test void deletePaperPhysicallyRemovesOwnedDirectory(){Paper p=new Paper(9L,1L,"p","p.pdf","x",1,1,"en","EXTRACTED",LocalDateTime.now(),LocalDateTime.now());when(papers.findOwnedById(1,9)).thenReturn(Optional.of(p));when(reviewMapper.selectList(any())).thenReturn(List.of());when(papers.deleteOwnedById(1,9)).thenReturn(true);when(storage.paperDirectory(1,9)).thenReturn(Path.of("storage/papers/1/9"));service.deletePaper(1,9);verify(storage).deleteDirectory(Path.of("storage/papers/1/9"));}
}
